#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, C; scanf("%d %d", &N, &C);
        char *s = (char*)malloc(N+5);
        scanf("%s", s);
        int *pos = (int*)malloc(N*sizeof(int));
        int cnt = 0;
        for(int i=0;i<N;i++) if(s[i]=='1') pos[cnt++] = i;
        if(cnt<=1){
            printf("YES\n");
            free(s); free(pos);
            continue;
        }
        int bad = 0;
        for(int i=0;i<cnt;i++){
            int cur = pos[i];
            int nxt = pos[(i+1)%cnt];
            int gap = (i+1==cnt) ? (pos[0] + N - cur - 1) : (nxt - cur - 1);
            if(gap > C) bad++;
        }
        printf(bad<=1?"YES\n":"NO\n");
        free(s); free(pos);
    }
    return 0;
}

